{"content":"const std = @import("std");
const LayoutCell = @import("layout/layout.zig").LayoutCell;
const CellType = @import("layout/layout.zig").CellType;
const CopyState = @import("copy/copy.zig").CopyState;
const ModeTree = @import("mode/tree.zig").ModeTree;

pub const PromptState = struct {
    buffer: [512]u8 = .{0} ** 512,
    len: usize = 0,
};

pub const ChooseTreeItem = struct {
    session: ?*anyopaque = null,
    window: ?*anyopaque = null,
    pane: ?*anyopaque = null,
    buffer_index: ?u32 = null,
};

pub const ChooseTreeState = struct {
    tree: ModeTree,
    items: std.ArrayListAligned(ChooseTreeItem, null),
    labels: std.ArrayListAligned([]u8, null),
    allocator: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator, visible_rows: u32) ChooseTreeState {
        return .{
            .tree = ModeTree.init(alloc, visible_rows),
            .items = .empty,
            .labels = .empty,
            .allocator = alloc,
        };
    }

    pub fn deinit(self: *ChooseTreeState) void {
        self.tree.deinit();
        for (self.labels.items) |label| {
            self.allocator.free(label);
        }
        self.labels.deinit(self.allocator);
        self.items.deinit(self.allocator);
    }
};

/// A pane within a window.
pub const Pane = struct {
    id: u32,
    pid: std.c.pid_t,
    fd: std.c.fd_t,
    pipe_fd: std.c.fd_t,

    sx: u32,
    sy: u32,
    xoff: u32,
    yoff: u32,

    flags: Flags,
    copy_state: ?CopyState,
    prompt_state: ?PromptState,
    choose_tree_state: ?ChooseTreeState,
    allocator: std.mem.Allocator,

    pub const Flags = packed struct(u16) {
        redraw: bool = false,
        focused: bool = false,
        exited: bool = false,
        empty: bool = false,
        input_disabled: bool = false,
        _padding: u11 = 0,
    };

    var next_id: u32 = 0;

    pub fn init(alloc: std.mem.Allocator, sx: u32, sy: u32) !*Pane {
        const p = try alloc.create(Pane);
        p.* = .{
            .id = next_id,
            .pid = 0,
            .fd = -1,
            .pipe_fd = -1,
            .sx = sx,
            .sy = sy,
            .xoff = 0,
            .yoff = 0,
            .flags = .{},
            .copy_state = null,
            .prompt_state = null,
            .choose_tree_state = null,
            .allocator = alloc,
        };
        next_id += 1;
        return p;
    }

    pub fn deinit(self: *Pane) void {
        if (self.fd >= 0) {
            _ = std.c.close(self.fd);
        }
        if (self.pipe_fd >= 0) {
            _ = std.c.close(self.pipe_fd);
        }
        if (self.choose_tree_state) |*state| {
            state.deinit();
        }
        self.allocator.destroy(self);
    }

    pub fn resize(self: *Pane, sx: u32, sy: u32) void {
        self.sx = sx;
        self.sy = sy;
        self.flags.redraw = true;
    }
};

/// A window containing one or more panes arranged in a layout.
pub const Window = struct {
    id: u32,
    name: []const u8,

    panes: std.ArrayListAligned(*Pane, null),
    active_pane: ?*Pane,
    last_pane: ?*Pane,

    layout_root: ?*LayoutCell,
    layout_preset_index: u3,

    sx: u32,
    sy: u32,

    options: Options,
    flags: Flags,
    allocator: std.mem.Allocator,

    pub const Options = struct {
        mode_keys: []u8,
        window_status_format: []u8,
        aggressive_resize: bool = false,
        remain_on_exit: bool = false,
    };

    pub const Flags = packed struct(u16) {
        bell: bool = false,
        activity: bool = false,
        silence: bool = false,
        zoomed: bool = false,
        _padding: u12 = 0,
    };

    var next_id: u32 = 0;

    pub fn init(alloc: std.mem.Allocator, name: []const u8, sx: u32, sy: u32) !*Window {
        const w = try alloc.create(Window);
        errdefer alloc.destroy(w);
        const owned_name = try alloc.dupe(u8, name);
        errdefer alloc.free(owned_name);
        const mode_keys = try alloc.dupe(u8, "emacs");
        errdefer alloc.free(mode_keys);
        const window_status_format = try alloc.dupe(u8, "#I:#W#F");
        errdefer alloc.free(window_status_format);
        w.* = .{
            .id = next_id,
            .name = owned_name,
            .panes = .empty,
            .active_pane = null,
            .last_pane = null,
            .layout_root = null,
            .layout_preset_index = 0,
            .sx = sx,
            .sy = sy,
            .options = .{
                .mode_keys = mode_keys,
                .window_status_format = window_status_format,
            },
            .flags = .{},
            .allocator = alloc,
        };
        next_id += 1;
        return w;
    }

    pub fn deinit(self: *Window) void {
        for (self.panes.items) |p| {
            p.deinit();
        }
        self.panes.deinit(self.allocator);
        if (self.layout_root) |root| {
            root.deinit();
        }
        self.allocator.free(self.options.mode_keys);
        self.allocator.free(self.options.window_status_format);
        self.allocator.free(self.name);
        self.allocator.destroy(self);
    }

    /// Add a pane to the window.
    pub fn addPane(self: *Window, pane: *Pane) !void {
        try self.panes.append(self.allocator, pane);
        if (self.active_pane == null) {
            self.active_pane = pane;
        }
        if (self.layout_root == null) {
            self.layout_root = try LayoutCell.initLeaf(self.allocator, pane.id, self.sx, self.sy, 0, 0);
        }
    }

    /// Get the number of panes.
    pub fn paneCount(self: *const Window) usize {
        return self.panes.items.len;
    }

    /// Select the next pane.
    pub fn nextPane(self: *Window) void {
        if (self.panes.items.len == 0) return;
        if (self.active_pane) |active| {
            for (self.panes.items, 0..) |p, i| {
                if (p == active) {
                    const next_idx = (i + 1) % self.panes.items.len;
                    self.active_pane = self.panes.items[next_idx];
                    if (self.flags.zoomed) self.applyZoomLayout();
                    return;
                }
            }
        }
        self.active_pane = self.panes.items[0];
        if (self.flags.zoomed) self.applyZoomLayout();
    }

    /// Select the previous pane.
    pub fn prevPane(self: *Window) void {
        if (self.panes.items.len == 0) return;
        if (self.active_pane) |active| {
            for (self.panes.items, 0..) |p, i| {
                if (p == active) {
                    const prev_idx = if (i == 0) self.panes.items.len - 1 else i - 1;
                    self.active_pane = self.panes.items[prev_idx];
                    if (self.flags.zoomed) self.applyZoomLayout();
                    return;
                }
            }
        }
    }

    pub fn selectPane(self: *Window, pane: *Pane) void {
        if (self.active_pane) |current| {
            if (current != pane) self.last_pane = current;
        }
        self.active_pane = pane;
        pane.flags.focused = true;
        if (self.flags.zoomed) self.applyZoomLayout();
    }

    pub fn selectPaneByIndex(self: *Window, index: usize) bool {
        if (index >= self.panes.items.len) return false;
        self.selectPane(self.panes.items[index]);
        return true;
    }

    pub fn selectPaneById(self: *Window, pane_id: u32) bool {
        for (self.panes.items) |pane| {
            if (pane.id == pane_id) {
                self.selectPane(pane);
                return true;
            }
        }
        return false;
    }

    /// Remove and destroy a pane. Returns true if the window has no panes left.
    pub fn removePane(self: *Window, pane: *Pane) bool {
        if (self.last_pane == pane) self.last_pane = null;

        for (self.panes.items, 0..) |p, i| {
            if (p == pane) {
                _ = self.panes.orderedRemove(i);
                break;
            }
        }

        // If active pane was removed, select another
        if (self.active_pane == pane) {
            self.active_pane = if (self.panes.items.len > 0) self.panes.items[0] else null;
        }

        pane.deinit();
        return self.panes.items.len == 0;
    }

    pub const SwapDirection = enum { next, prev };

    /// Swap the active pane with the next or previous pane.
    pub fn swapActivePane(self: *Window, direction: SwapDirection) void {
        if (self.panes.items.len < 2) return;
        const active = self.active_pane orelse return;

        for (self.panes.items, 0..) |p, i| {
            if (p == active) {
                const other_idx = switch (direction) {
                    .next => (i + 1) % self.panes.items.len,
                    .prev => if (i == 0) self.panes.items.len - 1 else i - 1,
                };
                // Swap pane pointers in the list
                self.panes.items[i] = self.panes.items[other_idx];
                self.panes.items[other_idx] = active;

                // Swap positions
                const tmp_xoff = active.xoff;
                const tmp_yoff = active.yoff;
                const tmp_sx = active.sx;
                const tmp_sy = active.sy;
                active.xoff = self.panes.items[i].xoff;
                active.yoff = self.panes.items[i].yoff;
                active.sx = self.panes.items[i].sx;
                active.sy = self.panes.items[i].sy;
                self.panes.items[i].xoff = tmp_xoff;
                self.panes.items[i].yoff = tmp_yoff;
                self.panes.items[i].sx = tmp_sx;
                self.panes.items[i].sy = tmp_sy;

                active.flags.redraw = true;
                self.panes.items[i].flags.redraw = true;
                return;
            }
        }
    }

    /// Resize the window and all panes.
    pub fn resize(self: *Window, new_sx: u32, new_sy: u32) void {
        self.sx = new_sx;
        self.sy = new_sy;
        if (self.flags.zoomed) {
            self.applyZoomLayout();
        } else if (self.layout_root) |root| {
            root.resize(new_sx, new_sy);
            self.syncPanesFromLayout();
        }
    }

    pub fn splitActivePane(self: *Window, new_pane: *Pane, direction: CellType, percent: u32) !void {
        const active = self.active_pane orelse {
            try self.addPane(new_pane);
            return;
        };

        if (self.layout_root == null) {
            self.layout_root = try LayoutCell.initLeaf(self.allocator, active.id, self.sx, self.sy, 0, 0);
        }

        const root = self.layout_root.?;
        const target = root.findPane(active.id) orelse return error.PaneNotFound;
        _ = try target.split(direction, new_pane.id, percent);
        try self.panes.append(self.allocator, new_pane);
        self.active_pane = new_pane;
        if (self.flags.zoomed) {
            self.applyZoomLayout();
        } else {
            self.syncPanesFromLayout();
        }
    }

    pub fn syncPanesFromLayout(self: *Window) void {
        const root = self.layout_root orelse return;
        for (self.panes.items) |pane| {
            if (root.findPane(pane.id)) |cell| {
                pane.xoff = cell.xoff;
                pane.yoff = cell.yoff;
                pane.sx = cell.sx;
                pane.sy = cell.sy;
                pane.flags.redraw = true;
            }
        }
    }

    fn applyZoomLayout(self: *Window) void {
        const active = self.active_pane orelse return;
        for (self.panes.items) |pane| {
            if (pane == active) {
                pane.xoff = 0;
                pane.yoff = 0;
                pane.sx = self.sx;
                pane.sy = self.sy;
            } else {
                pane.xoff = 0;
                pane.yoff = 0;
                pane.sx = 0;
                pane.sy = 0;
            }
            pane.flags.redraw = true;
        }
    }

    pub fn toggleZoom(self: *Window) bool {
        if (self.active_pane == null) return self.flags.zoomed;
        self.flags.zoomed = !self.flags.zoomed;
        if (self.flags.zoomed) {
            self.applyZoomLayout();
        } else if (self.layout_root) |root| {
            root.resize(self.sx, self.sy);
            self.syncPanesFromLayout();
        }
        return self.flags.zoomed;
    }

    /// Rename the window.
    pub fn rename(self: *Window, new_name: []const u8) !void {
        const owned = try self.allocator.dupe(u8, new_name);
        self.allocator.free(self.name);
        self.name = owned;
    }

    pub fn setModeKeys(self: *Window, value: []const u8) !void {
        const owned = try self.allocator.dupe(u8, value);
        self.allocator.free(self.options.mode_keys);
        self.options.mode_keys = owned;
    }

    pub fn setWindowStatusFormat(self: *Window, value: []const u8) !void {
        const owned = try self.allocator.dupe(u8, value);
        self.allocator.free(self.options.window_status_format);
        self.options.window_status_format = owned;
    }
};

test "window and pane lifecycle" {
    const alloc = std.testing.allocator;
    var w = try Window.init(alloc, "test", 80, 24);
    defer w.deinit();

    const p1 = try Pane.init(alloc, 80, 24);
    try w.addPane(p1);
    try std.testing.expectEqual(@as(usize, 1), w.paneCount());
    try std.testing.expect(w.active_pane == p1);

    const p2 = try Pane.init(alloc, 40, 24);
    try w.addPane(p2);
    try std.testing.expectEqual(@as(usize, 2), w.paneCount());
}

test "splitActivePane updates layout and active pane" {
    const alloc = std.testing.allocator;
    var w = try Window.init(alloc, "test", 80, 24);
    defer w.deinit();

    const p1 = try Pane.init(alloc, 80, 24);
    try w.addPane(p1);

    const p2 = try Pane.init(alloc, 80, 24);
    try w.splitActivePane(p2, .horizontal, 50);

    try std.testing.expectEqual(@as(usize, 2), w.paneCount());
    try std.testing.expect(w.active_pane == p2);
    try std.testing.expect(w.layout_root != null);
    try std.testing.expect(p1.sx > 0);
    try std.testing.expect(p2.sx > 0);
}

test "toggleZoom zooms and restores active pane geometry" {
    const alloc = std.testing.allocator;
    var w = try Window.init(alloc, "zoom", 80, 24);
    defer w.deinit();

    const p1 = try Pane.init(alloc, 80, 24);
    try w.addPane(p1);
    const p2 = try Pane.init(alloc, 80, 24);
    try w.splitActivePane(p2, .horizontal, 50);

    const left_width = p1.sx;
    const right_width = p2.sx;
    try std.testing.expectEqual(@as(u32, 40), left_width);
    try std.testing.expectEqual(@as(u32, 39), right_width);

    try std.testing.expectEqual(true, w.toggleZoom());
    try std.testing.expect(w.flags.zoomed);
    try std.testing.expectEqual(@as(u32, 80), p2.sx);
    try std.testing.expectEqual(@as(u32, 24), p2.sy);
    try std.testing.expectEqual(@as(u32, 0), p1.sx);
    try std.testing.expectEqual(@as(u32, 0), p1.sy);

    try std.testing.expectEqual(false, w.toggleZoom());
    try std.testing.expect(!w.flags.zoomed);
    try std.testing.expect(p1.sx > 0);
    try std.testing.expect(p2.sx > 0);
    try std.testing.expectEqual(@as(u32, 79), p1.sx + p2.sx);
}"}

{"content":"const std = @import("std");
const Window = @import("window.zig").Window;
const Pane = @import("window.zig").Pane;
const Environ = @import("core/environ.zig").Environ;
const Style = @import("status/style.zig").Style;

/// An agentmux session. Contains windows and tracks attached clients.
extern "c" fn time(timer: ?*i64) i64;

pub const Session = struct {
    id: u32,
    name: []const u8,
    created_at: i64,

    windows: std.ArrayListAligned(*Window, null),
    active_window: ?*Window,
    last_window: ?*Window,

    attached: u32,
    flags: Flags,

    options: Options,
    environ: Environ,

    allocator: std.mem.Allocator,

    pub const Flags = packed struct(u8) {
        alerted: bool = false,
        _padding: u7 = 0,
    };

    pub const Options = struct {
        base_index: u32 = 0,
        default_shell: [:0]u8,
        status: bool = true,
        mouse: bool = false,
        prefix_key: u21 = 0x02, // C-b
        prefix2_key: ?u21 = null,
        prefix_string: []u8,
        status_style: Style = .{
            .fg = .green,
            .bg = .black,
            .attrs = .{},
        },
        status_left: []u8,
        status_right: []u8,
        visual_activity: bool = false,
    };

    var next_id: u32 = 0;

    pub fn init(alloc: std.mem.Allocator, name: []const u8) !*Session {
        const s = try alloc.create(Session);
        errdefer alloc.destroy(s);

        const owned_name = try alloc.dupe(u8, name);
        errdefer alloc.free(owned_name);
        const shell_env = std.c.getenv("SHELL");
        const shell_str = if (shell_env) |sh| std.mem.sliceTo(sh, 0) else "/bin/sh";
        const default_shell = try alloc.dupeZ(u8, if (shell_str.len > 0) shell_str else "/bin/sh");
        errdefer alloc.free(default_shell);
        const prefix_string = try alloc.dupe(u8, "C-b");
        errdefer alloc.free(prefix_string);
        const status_left = try alloc.dupe(u8, "[#S]");
        errdefer alloc.free(status_left);
        const status_right = try alloc.dupe(u8, "#H");
        errdefer alloc.free(status_right);

        var now: i64 = 0;
        _ = time(&now);

        s.* = .{
            .id = next_id,
            .name = owned_name,
            .created_at = now,
            .windows = .empty,
            .active_window = null,
            .last_window = null,
            .attached = 0,
            .flags = .{},
            .options = .{
                .default_shell = default_shell,
                .prefix_string = prefix_string,
                .status_left = status_left,
                .status_right = status_right,
            },
            .environ = Environ.init(alloc),
            .allocator = alloc,
        };
        next_id += 1;
        return s;
    }

    pub fn deinit(self: *Session) void {
        for (self.windows.items) |w| {
            w.deinit();
        }
        self.windows.deinit(self.allocator);
        self.environ.deinit();
        self.allocator.free(self.options.default_shell);
        self.allocator.free(self.options.prefix_string);
        self.allocator.free(self.options.status_left);
        self.allocator.free(self.options.status_right);
        self.allocator.free(self.name);
        self.allocator.destroy(self);
    }

    /// Add a window to the session.
    pub fn addWindow(self: *Session, window: *Window) !void {
        try self.windows.append(self.allocator, window);
        if (self.active_window == null) {
            self.active_window = window;
        }
    }

    /// Find a window by index.
    pub fn findWindow(self: *const Session, index: u32) ?*Window {
        for (self.windows.items) |w| {
            if (w.id == index) return w;
        }
        return null;
    }

    /// Find a window by its displayed number (base-index-adjusted position).
    pub fn findWindowByNumber(self: *const Session, number: u32) ?*Window {
        if (number < self.options.base_index) return null;
        const offset = number - self.options.base_index;
        if (offset >= self.windows.items.len) return null;
        return self.windows.items[offset];
    }

    /// Get the number of windows.
    pub fn windowCount(self: *const Session) usize {
        return self.windows.items.len;
    }

    /// Select the next window.
    pub fn nextWindow(self: *Session) void {
        if (self.windows.items.len == 0) return;
        if (self.active_window) |active| {
            for (self.windows.items, 0..) |w, i| {
                if (w == active) {
                    const next_idx = (i + 1) % self.windows.items.len;
                    self.active_window = self.windows.items[next_idx];
                    return;
                }
            }
        }
        self.active_window = self.windows.items[0];
    }

    /// Select the previous window.
    pub fn prevWindow(self: *Session) void {
        if (self.windows.items.len == 0) return;
        if (self.active_window) |active| {
            for (self.windows.items, 0..) |w, i| {
                if (w == active) {
                    const prev_idx = if (i == 0) self.windows.items.len - 1 else i - 1;
                    self.active_window = self.windows.items[prev_idx];
                    return;
                }
            }
        }
    }

    /// Select a specific window, tracking the previous one.
    pub fn selectWindow(self: *Session, window: *Window) void {
        if (self.active_window) |current| {
            if (current != window) {
                self.last_window = current;
            }
        }
        self.active_window = window;
    }

    /// Switch to the last active window.
    pub fn lastWindow(self: *Session) bool {
        if (self.last_window) |last| {
            // Verify it's still in the window list
            for (self.windows.items) |w| {
                if (w == last) {
                    self.selectWindow(last);
                    return true;
                }
            }
            self.last_window = null;
        }
        return false;
    }

    /// Remove and destroy a window. Returns true if the session has no windows left.
    pub fn removeWindow(self: *Session, window: *Window) bool {
        // If this was the last_window, clear it
        if (self.last_window == window) {
            self.last_window = null;
        }

        for (self.windows.items, 0..) |w, i| {
            if (w == window) {
                _ = self.windows.orderedRemove(i);
                break;
            }
        }

        // If active window was removed, select another
        if (self.active_window == window) {
            self.active_window = if (self.windows.items.len > 0) self.windows.items[0] else null;
        }

        window.deinit();
        return self.windows.items.len == 0;
    }

    /// Rename the session.
    pub fn rename(self: *Session, new_name: []const u8) !void {
        const owned = try self.allocator.dupe(u8, new_name);
        self.allocator.free(self.name);
        self.name = owned;
    }

    pub fn setDefaultShell(self: *Session, shell: []const u8) !void {
        const owned = try self.allocator.dupeZ(u8, shell);
        self.allocator.free(self.options.default_shell);
        self.options.default_shell = owned;
    }

    pub fn setPrefix(self: *Session, prefix_string: []const u8, prefix_key: u21) !void {
        const owned = try self.allocator.dupe(u8, prefix_string);
        self.allocator.free(self.options.prefix_string);
        self.options.prefix_string = owned;
        self.options.prefix_key = prefix_key;
    }

    pub fn setStatusLeft(self: *Session, value: []const u8) !void {
        const owned = try self.allocator.dupe(u8, value);
        self.allocator.free(self.options.status_left);
        self.options.status_left = owned;
    }

    pub fn setStatusRight(self: *Session, value: []const u8) !void {
        const owned = try self.allocator.dupe(u8, value);
        self.allocator.free(self.options.status_right);
        self.options.status_right = owned;
    }
};

test "findWindowByNumber uses base index" {
    const alloc = std.testing.allocator;
    var session = try Session.init(alloc, "demo");
    defer session.deinit();
    session.options.base_index = 1;

    var w1 = try Window.init(alloc, "one", 80, 24);
    var w2 = try Window.init(alloc, "two", 80, 24);

    const p1 = try Pane.init(alloc, 80, 24);
    const p2 = try Pane.init(alloc, 80, 24);
    try w1.addPane(p1);
    try w2.addPane(p2);
    try session.addWindow(w1);
    try session.addWindow(w2);

    try std.testing.expect(session.findWindowByNumber(0) == null);
    try std.testing.expect(session.findWindowByNumber(1) == w1);
    try std.testing.expect(session.findWindowByNumber(2) == w2);
}"}

{"content":"const std = @import("std");

/// Protocol version. Incremented on breaking changes.
pub const version: u32 = 1;

/// Maximum message payload size.
pub const max_payload: usize = 65536;

/// Message types sent between client and server.
pub const MessageType = enum(u16) {
    // Client -> Server
    identify = 100,
    command = 101,
    resize = 102,
    key = 103,
    shell = 104,
    exit = 105,
    exiting = 106,

    // Server -> Client
    version = 200,
    ready = 201,
    output = 202,
    pause = 203,
    detach = 204,
    shutdown = 205,
    error_msg = 206,
    exit_ack = 207,
};

/// Wire format header for all messages.
pub const Header = extern struct {
    msg_type: u16 align(1),
    payload_len: u32 align(1),
    flags: u16 align(1),
};

pub const Message = struct {
    msg_type: MessageType,
    flags: u16,
    payload: []u8,
    allocator: std.mem.Allocator,

    pub fn deinit(self: *Message) void {
        self.allocator.free(self.payload);
        self.* = undefined;
    }
};

comptime {
    std.debug.assert(@sizeOf(Header) == 8);
}

/// Identification message sent by client on connect.
pub const IdentifyMsg = extern struct {
    protocol_version: u32 align(1),
    pid: i32 align(1),
    flags: IdentifyFlags align(1),
    term_name: [64]u8 align(1),
    tty_name: [64]u8 align(1),
    cols: u16 align(1),
    rows: u16 align(1),
    xpixel: u16 align(1),
    ypixel: u16 align(1),
};

pub const IdentifyFlags = packed struct(u32) {
    utf8: bool = false,
    control_mode: bool = false,
    terminal_256: bool = false,
    _padding: u29 = 0,
};

pub const ResizeMsg = extern struct {
    cols: u16 align(1),
    rows: u16 align(1),
    xpixel: u16 align(1),
    ypixel: u16 align(1),
};

pub const KeyMsg = extern struct {
    key: u64 align(1),
    mouse_x: u16 align(1),
    mouse_y: u16 align(1),
    mouse_button: u8 align(1),
    mouse_flags: u8 align(1),
};

pub fn serializeHeader(header: Header) [8]u8 {
    var buf: [8]u8 = undefined;
    std.mem.writeInt(u16, buf[0..2], header.msg_type, .little);
    std.mem.writeInt(u32, buf[2..6], header.payload_len, .little);
    std.mem.writeInt(u16, buf[6..8], header.flags, .little);
    return buf;
}

pub fn deserializeHeader(buf: *const [8]u8) Header {
    return .{
        .msg_type = std.mem.readInt(u16, buf[0..2], .little),
        .payload_len = std.mem.readInt(u32, buf[2..6], .little),
        .flags = std.mem.readInt(u16, buf[6..8], .little),
    };
}

pub fn messageTypeFromInt(raw: u16) !MessageType {
    return switch (raw) {
        @intFromEnum(MessageType.identify) => .identify,
        @intFromEnum(MessageType.command) => .command,
        @intFromEnum(MessageType.resize) => .resize,
        @intFromEnum(MessageType.key) => .key,
        @intFromEnum(MessageType.shell) => .shell,
        @intFromEnum(MessageType.exit) => .exit,
        @intFromEnum(MessageType.exiting) => .exiting,
        @intFromEnum(MessageType.version) => .version,
        @intFromEnum(MessageType.ready) => .ready,
        @intFromEnum(MessageType.output) => .output,
        @intFromEnum(MessageType.pause) => .pause,
        @intFromEnum(MessageType.detach) => .detach,
        @intFromEnum(MessageType.shutdown) => .shutdown,
        @intFromEnum(MessageType.error_msg) => .error_msg,
        @intFromEnum(MessageType.exit_ack) => .exit_ack,
        else => error.InvalidMessageType,
    };
}

pub fn writeAll(fd: std.posix.fd_t, bytes: []const u8) !void {
    var written: usize = 0;
    while (written < bytes.len) {
        const rc = std.c.write(fd, bytes[written..].ptr, bytes.len - written);
        if (rc < 0) switch (std.posix.errno(rc)) {
            .INTR, .AGAIN => continue,
            else => return error.WriteFailed,
        };
        if (rc == 0) return error.WriteFailed;
        written += @intCast(rc);
    }
}

pub fn readExact(fd: std.posix.fd_t, buf: []u8) !void {
    var read_total: usize = 0;
    while (read_total < buf.len) {
        const rc = std.c.read(fd, buf[read_total..].ptr, buf.len - read_total);
        if (rc < 0) switch (std.posix.errno(rc)) {
            .INTR => continue,
            .AGAIN => return error.WouldBlock,
            else => return error.ReadFailed,
        };
        if (rc == 0) return error.UnexpectedEof;
        read_total += @intCast(rc);
    }
}

pub fn sendMessage(fd: std.posix.fd_t, msg_type: MessageType, payload: []const u8) !void {
    return sendMessageWithFlags(fd, msg_type, 0, payload);
}

pub fn sendMessageWithFlags(fd: std.posix.fd_t, msg_type: MessageType, flags: u16, payload: []const u8) !void {
    if (payload.len > max_payload) return error.PayloadTooLarge;

    const header_bytes = serializeHeader(.{
        .msg_type = @intFromEnum(msg_type),
        .payload_len = @intCast(payload.len),
        .flags = flags,
    });
    try writeAll(fd, &header_bytes);
    if (payload.len > 0) {
        try writeAll(fd, payload);
    }
}

pub fn recvHeader(fd: std.posix.fd_t) !Header {
    var buf: [8]u8 = undefined;
    try readExact(fd, &buf);
    return deserializeHeader(&buf);
}

pub fn recvMessageAlloc(alloc: std.mem.Allocator, fd: std.posix.fd_t) !Message {
    const header = try recvHeader(fd);
    const msg_type = try messageTypeFromInt(header.msg_type);
    if (header.payload_len > max_payload) return error.PayloadTooLarge;

    const payload = try alloc.alloc(u8, header.payload_len);
    errdefer alloc.free(payload);
    if (payload.len > 0) {
        try readExact(fd, payload);
    }

    return .{
        .msg_type = msg_type,
        .flags = header.flags,
        .payload = payload,
        .allocator = alloc,
    };
}

pub fn encodeCommandArgs(alloc: std.mem.Allocator, args: []const []const u8) ![]u8 {
    var total: usize = 0;
    for (args) |arg| total += arg.len + 1;
    if (total > max_payload) return error.PayloadTooLarge;

    const payload = try alloc.alloc(u8, total);
    var offset: usize = 0;
    for (args) |arg| {
        @memcpy(payload[offset .. offset + arg.len], arg);
        offset += arg.len;
        payload[offset] = 0;
        offset += 1;
    }
    return payload;
}

pub fn decodeCommandArgs(alloc: std.mem.Allocator, payload: []const u8) !std.ArrayListAligned([]const u8, null) {
    var args: std.ArrayListAligned([]const u8, null) = .empty;
    errdefer args.deinit(alloc);

    if (payload.len == 0) return args;

    var start: usize = 0;
    for (payload, 0..) |byte, i| {
        if (byte != 0) continue;
        try args.append(alloc, payload[start..i]);
        start = i + 1;
    }

    if (start < payload.len) {
        try args.append(alloc, payload[start..]);
    }

    return args;
}

test "header roundtrip" {
    const h = Header{
        .msg_type = @intFromEnum(MessageType.identify),
        .payload_len = 1234,
        .flags = 7,
    };
    const bytes = serializeHeader(h);
    const h2 = deserializeHeader(&bytes);
    try std.testing.expectEqual(h.msg_type, h2.msg_type);
    try std.testing.expectEqual(h.payload_len, h2.payload_len);
    try std.testing.expectEqual(h.flags, h2.flags);
}

test "message roundtrip through pipe" {
    var fds: [2]std.c.fd_t = undefined;
    try std.testing.expectEqual(@as(i32, 0), std.c.pipe(&fds));
    defer _ = std.c.close(fds[0]);
    defer _ = std.c.close(fds[1]);

    try sendMessageWithFlags(fds[1], .output, 3, "hello");
    var msg = try recvMessageAlloc(std.testing.allocator, fds[0]);
    defer msg.deinit();

    try std.testing.expectEqual(MessageType.output, msg.msg_type);
    try std.testing.expectEqual(@as(u16, 3), msg.flags);
    try std.testing.expectEqualStrings("hello", msg.payload);
}

test "command arg payload roundtrip" {
    const input = [_][]const u8{ "new-session", "-s", "demo session" };
    const payload = try encodeCommandArgs(std.testing.allocator, &input);
    defer std.testing.allocator.free(payload);

    var decoded = try decodeCommandArgs(std.testing.allocator, payload);
    defer decoded.deinit(std.testing.allocator);

    try std.testing.expectEqual(@as(usize, input.len), decoded.items.len);
    for (input, decoded.items) |expected, actual| {
        try std.testing.expectEqualStrings(expected, actual);
    }
}"}

{"content":"const std = @import("std");
const format = @import("format.zig");
const style_mod = @import("style.zig");

/// Status bar configuration and rendering.
pub const StatusBar = struct {
    left: []const u8,
    right: []const u8,
    style: style_mod.Style,
    interval: u32, // refresh interval in seconds
    enabled: bool,

    pub const default_left = "[#S] ";
    pub const default_right = " %H:%M %d-%b-%y";

    pub fn init() StatusBar {
        return .{
            .left = default_left,
            .right = default_right,
            .style = style_mod.Style.default,
            .interval = 15,
            .enabled = true,
        };
    }

    /// Render the status bar for a given width.
    pub fn render(self: *const StatusBar, alloc: std.mem.Allocator, cols: u32, ctx: *const format.FormatContext) ![]u8 {
        if (!self.enabled or cols == 0) {
            return try alloc.alloc(u8, 0);
        }

        const left = try format.expand(alloc, self.left, ctx);
        defer alloc.free(left);
        const right = try format.expand(alloc, self.right, ctx);
        defer alloc.free(right);

        // Build the status line: left + padding + right
        var line: std.ArrayListAligned(u8, null) = .empty;
        errdefer line.deinit(alloc);

        // Add left section
        const left_len = @min(left.len, cols);
        try line.appendSlice(alloc, left[0..left_len]);

        // Calculate padding
        const right_len = @min(right.len, cols);
        const used = left_len + right_len;
        if (used < cols) {
            // Fill middle with spaces
            const padding = cols - @as(u32, @intCast(used));
            var p: u32 = 0;
            while (p < padding) : (p += 1) {
                try line.append(alloc, ' ');
            }
        }

        // Add right section
        try line.appendSlice(alloc, right[0..right_len]);

        return try line.toOwnedSlice(alloc);
